for (j in seq_len(k - 1)) {
  denom <- hpx[j] - hpx[j + 1]
  ## Near-parallel tangents (locally linear h) meet nowhere useful; the
  ## envelope value is identical for any z in the interval, so use the
  ## midpoint.  Otherwise clamp the intersection into [x_j, x_{j+1}],
  ## where a concave h guarantees it lies, guarding against round-off.
  if (denom <= 1e-8 * (1 + abs(hpx[j]))) {
    z[j] <- 0.5 * (x[j] + x[j + 1])
  } else {
    zj <- (hx[j + 1] - hx[j] - x[j + 1] * hpx[j + 1] + x[j] * hpx[j]) / denom
    z[j] <- min(max(zj, x[j]), x[j + 1])
  }
}

